dashboard.definition:
{
  "title": "Source - WinEventLog",
  "description": "Windows Event Logs — detect brute force attacks, track privileged account usage, audit system changes",
  "dataSources": {
    "ds_total_events": {
      "type": "ds.search",
      "name": "Total WinEventLog Events Over Time",
      "options": {
        "query": "| tstats count where index=fake_tshrt sourcetype=\"FAKE:WinEventLog\" by _time span=1h"
      }
    },
    "ds_security_events": {
      "type": "ds.search",
      "name": "Security Events",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:WinEventLog\" (EventCode=4625 OR EventCode=4624 OR EventCode=4720) | stats count"
      }
    },
    "ds_failed_logons": {
      "type": "ds.search",
      "name": "Failed Logons",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:WinEventLog\" EventCode=4625 | stats count"
      }
    },
    "ds_account_lockouts": {
      "type": "ds.search",
      "name": "Account Lockouts",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:WinEventLog\" EventCode=4740 | stats count"
      }
    },
    "ds_events_over_time": {
      "type": "ds.search",
      "name": "Events Over Time by EventCode",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:WinEventLog\" | timechart span=1h count by EventCode limit=8"
      }
    },
    "ds_events_by_log": {
      "type": "ds.search",
      "name": "Events by Log",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:WinEventLog\" source=* | stats count by source | sort -count | rename source as \"Log\""
      }
    },
    "ds_top_failed_accounts": {
      "type": "ds.search",
      "name": "Top Failed Logon Accounts",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:WinEventLog\" EventCode=4625 user=* | stats count by user | sort -count | head 15 | rename user as \"Account\""
      }
    },
    "ds_sample_events": {
      "type": "ds.search",
      "name": "Recent Security Events",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:WinEventLog\" | table _time host EventCode user src Message | sort -_time | head 30 | rename host as \"Host\" EventCode as \"Event Code\" user as \"User\" src as \"Source IP\" Message as \"Message\""
      }
    }
  },
  "visualizations": {
    "viz_header": {
      "type": "splunk.markdown",
      "options": {
        "markdown": "# Source — WinEventLog\n\n**Sourcetype:** `FAKE:WinEventLog` | **Coverage:** Security, System, Application logs across all Windows servers | **Format:** XML\n\n**Why monitor?** Detect brute force attacks through failed logon patterns, track privileged account usage for compliance, and audit system changes to catch unauthorized modifications.",
        "fontColor": "#C3CBD4"
      }
    },
    "viz_kpi_total_events": {
      "type": "splunk.singlevalue",
      "title": "Total Events",
      "dataSources": { "primary": "ds_total_events" },
      "options": {
        "majorValue": "> sparklineValues | lastPoint()",
        "sparklineValues": "> primary | seriesByName('count')",
        "sparklineDisplay": "below",
        "majorColor": "#00D2FF",
        "backgroundColor": "transparent",
        "showSparklineAreaGraph": true,
        "sparklineStrokeColor": "#00D2FF"
      }
    },
    "viz_kpi_security_events": {
      "type": "splunk.singlevalue",
      "title": "Security Events",
      "dataSources": { "primary": "ds_security_events" },
      "options": {
        "majorValue": "> primary | seriesByName('count') | lastPoint()",
        "majorColor": "#F8BE34",
        "backgroundColor": "transparent",
        "sparklineDisplay": "off"
      }
    },
    "viz_kpi_failed_logons": {
      "type": "splunk.singlevalue",
      "title": "Failed Logons (4625)",
      "dataSources": { "primary": "ds_failed_logons" },
      "options": {
        "majorValue": "> primary | seriesByName('count') | lastPoint()",
        "majorColor": "#DC4E41",
        "backgroundColor": "transparent",
        "sparklineDisplay": "off"
      }
    },
    "viz_kpi_lockouts": {
      "type": "splunk.singlevalue",
      "title": "Account Lockouts (4740)",
      "dataSources": { "primary": "ds_account_lockouts" },
      "options": {
        "majorValue": "> primary | seriesByName('count') | lastPoint()",
        "majorColor": "#7B56DB",
        "backgroundColor": "transparent",
        "sparklineDisplay": "off"
      }
    },
    "viz_events_over_time": {
      "type": "splunk.area",
      "title": "Events Over Time by EventCode",
      "dataSources": { "primary": "ds_events_over_time" },
      "options": {
        "stackMode": "stacked",
        "legendDisplay": "right",
        "nullValueDisplay": "zero",
        "areaOpacity": 0.7,
        "backgroundColor": "transparent",
        "xAxisTitleVisibility": "hide",
        "yAxisTitleText": "Events / hour",
        "yAxisTitleVisibility": "show",
        "yAxisAbbreviation": "auto",
        "seriesColors": ["#53A051", "#00D2FF", "#DC4E41", "#F8BE34", "#7B56DB", "#009CEB", "#F1813F", "#00CDAF"]
      },
      "showProgressBar": true,
      "showLastUpdated": true
    },
    "viz_events_by_log": {
      "type": "splunk.pie",
      "title": "Events by Log",
      "dataSources": { "primary": "ds_events_by_log" },
      "options": {
        "labelDisplay": "valuesAndPercentage",
        "showDonutHole": true,
        "seriesColors": ["#53A051", "#00D2FF", "#DC4E41", "#F8BE34", "#7B56DB", "#009CEB", "#F1813F", "#00CDAF"]
      }
    },
    "viz_top_failed_accounts": {
      "type": "splunk.bar",
      "title": "Top Failed Logon Accounts",
      "dataSources": { "primary": "ds_top_failed_accounts" },
      "options": {
        "seriesColors": ["#DC4E41"],
        "legendDisplay": "off",
        "xAxisTitleText": "Failed Logons",
        "xAxisTitleVisibility": "show",
        "yAxisTitleVisibility": "hide",
        "backgroundColor": "transparent"
      },
      "showProgressBar": true
    },
    "viz_sample_header": {
      "type": "splunk.markdown",
      "options": {
        "markdown": "### Recent Security Events",
        "fontColor": "#C3CBD4"
      }
    },
    "viz_sample_events": {
      "type": "splunk.table",
      "title": "Recent Security Events",
      "dataSources": { "primary": "ds_sample_events" },
      "options": {
        "count": 20,
        "showRowNumbers": false
      },
      "showProgressBar": true,
      "showLastUpdated": true
    }
  },
  "inputs": {
    "input_global_trp": {
      "type": "input.timerange",
      "title": "Time Range",
      "options": {
        "token": "global_time",
        "defaultValue": "1767225600,1769904000"
      }
    }
  },
  "defaults": {
    "dataSources": {
      "ds.search": {
        "options": {
          "queryParameters": {
            "earliest": "$global_time.earliest$",
            "latest": "$global_time.latest$"
          }
        }
      }
    }
  },
  "layout": {
    "type": "grid",
    "globalInputs": ["input_global_trp"],
    "structure": [
      { "item": "viz_header", "type": "block", "position": { "x": 0, "y": 0, "w": 1200, "h": 150 } },
      { "item": "viz_kpi_total_events", "type": "block", "position": { "x": 0, "y": 150, "w": 300, "h": 120 } },
      { "item": "viz_kpi_security_events", "type": "block", "position": { "x": 300, "y": 150, "w": 300, "h": 120 } },
      { "item": "viz_kpi_failed_logons", "type": "block", "position": { "x": 600, "y": 150, "w": 300, "h": 120 } },
      { "item": "viz_kpi_lockouts", "type": "block", "position": { "x": 900, "y": 150, "w": 300, "h": 120 } },
      { "item": "viz_events_over_time", "type": "block", "position": { "x": 0, "y": 270, "w": 750, "h": 350 } },
      { "item": "viz_events_by_log", "type": "block", "position": { "x": 750, "y": 270, "w": 450, "h": 350 } },
      { "item": "viz_top_failed_accounts", "type": "block", "position": { "x": 0, "y": 620, "w": 1200, "h": 300 } },
      { "item": "viz_sample_header", "type": "block", "position": { "x": 0, "y": 920, "w": 1200, "h": 50 } },
      { "item": "viz_sample_events", "type": "block", "position": { "x": 0, "y": 970, "w": 1200, "h": 400 } }
    ]
  }
}
